def split_csv_line(line):
    fields = []
    buf = []
    i = 0
    n = len(line)
    while True:
        if i < n and line[i] == '"':
            i += 1
            closed = False
            while i < n:
                ch = line[i]
                if ch == '"':
                    if i + 1 < n and line[i + 1] == '"':
                        buf.append('"')
                        i += 2
                    else:
                        i += 1
                        closed = True
                        break
                else:
                    buf.append(ch)
                    i += 1
            if not closed:
                raise ValueError("unterminated quoted field")
            if i < n and line[i] != ',':
                raise ValueError("unexpected character after closing quote")
        else:
            while i < n and line[i] != ',':
                if line[i] == '"':
                    raise ValueError("quote inside unquoted field")
                buf.append(line[i])
                i += 1
        fields.append(''.join(buf))
        buf = []
        if i < n:
            i += 1
        else:
            break
    return fields

def parse_duration_strict(s):
    order = {'h': 0, 'm': 1, 's': 2}
    mult = {'h': 3600, 'm': 60, 's': 1}
    if s == "":
        raise ValueError("empty duration")
    i = 0
    n = len(s)
    last = -1
    total = 0
    first = True
    while i < n:
        j = i
        while j < n and '0' <= s[j] <= '9':
            j += 1
        if j == i:
            raise ValueError("expected digits")
        num = s[i:j]
        if len(num) > 1 and num[0] == '0':
            raise ValueError("leading zeros")
        if j >= n:
            raise ValueError("digits without a unit")
        unit = s[j]
        if unit not in order:
            raise ValueError("unknown unit")
        if order[unit] <= last:
            raise ValueError("unit out of order or duplicated")
        last = order[unit]
        val = int(num)
        if not first and unit in ('m', 's') and val > 59:
            raise ValueError("non-leading component out of range")
        total += val * mult[unit]
        first = False
        i = j + 1
    return total

