def tokenize_quoted(s):
    tokens = []
    buf = []
    started = False
    i = 0
    n = len(s)
    while i < n:
        ch = s[i]
        if ch == ' ' or ch == '\t':
            if started:
                tokens.append(''.join(buf))
                buf = []
                started = False
            i += 1
        elif ch == "'":
            started = True
            i += 1
            j = s.find("'", i)
            if j == -1:
                raise ValueError("unterminated single quote")
            buf.append(s[i:j])
            i = j + 1
        elif ch == '"':
            started = True
            i += 1
            closed = False
            while i < n:
                c = s[i]
                if c == '"':
                    i += 1
                    closed = True
                    break
                if c == '\\':
                    if i + 1 >= n:
                        raise ValueError("unterminated double quote")
                    nxt = s[i + 1]
                    if nxt == '"' or nxt == '\\':
                        buf.append(nxt)
                        i += 2
                    else:
                        raise ValueError("invalid escape in double quotes")
                else:
                    buf.append(c)
                    i += 1
            if not closed:
                raise ValueError("unterminated double quote")
        elif ch == '\\':
            if i + 1 >= n:
                raise ValueError("trailing backslash")
            started = True
            buf.append(s[i + 1])
            i += 2
        else:
            started = True
            buf.append(ch)
            i += 1
    if started:
        tokens.append(''.join(buf))
    return tokens

def unfold_headers(lines):
    def valid_name(name):
        if not name:
            return False
        for ch in name:
            if not ('A' <= ch <= 'Z' or 'a' <= ch <= 'z' or '0' <= ch <= '9' or ch == '-'):
                return False
        return True

    result = []
    current = None
    for line in lines:
        if line[:1] in (' ', '\t'):
            if current is None:
                raise ValueError("continuation before any header line")
            chunk = line.strip()
            if not chunk:
                raise ValueError("blank continuation line")
            current[1].append(chunk)
        else:
            if current is not None:
                result.append((current[0], ' '.join(current[1])))
            if ':' not in line:
                raise ValueError("header line missing colon")
            name, _, value = line.partition(':')
            if not valid_name(name):
                raise ValueError("invalid header name")
            v = value.strip()
            current = (name.lower(), [v] if v else [])
    if current is not None:
        result.append((current[0], ' '.join(current[1])))
    return result

def canonical_decimal(s):
    def read_digits(t):
        if not t:
            return ''
        if t[0] == '_' or t[-1] == '_':
            raise ValueError("misplaced underscore")
        out = []
        prev = ''
        for ch in t:
            if ch == '_':
                if prev == '_':
                    raise ValueError("doubled underscore")
            elif '0' <= ch <= '9':
                out.append(ch)
            else:
                raise ValueError("invalid character")
            prev = ch
        return ''.join(out)

    if not s:
        raise ValueError("empty input")
    i = 0
    sign = ''
    if s[0] in '+-':
        sign = s[0]
        i = 1
    body = s[i:]
    if body.count('.') > 1:
        raise ValueError("multiple dots")
    if '.' in body:
        int_part, frac_part = body.split('.')
    else:
        int_part, frac_part = body, ''
    ip = read_digits(int_part)
    fp = read_digits(frac_part)
    if not ip and not fp:
        raise ValueError("no digits")
    ip = ip.lstrip('0') or '0'
    fp = fp.rstrip('0')
    if ip == '0' and fp == '':
        return '0'
    out = ip
    if fp:
        out += '.' + fp
    if sign == '-':
        out = '-' + out
    return out

def parse_template_fields(s):
    out = []
    text = []

    def flush():
        if text:
            out.append(('text', ''.join(text)))
            text.clear()

    i = 0
    n = len(s)
    while i < n:
        ch = s[i]
        if ch == '{':
            if i + 1 < n and s[i + 1] == '{':
                text.append('{')
                i += 2
                continue
            j = s.find('}', i + 1)
            if j == -1:
                raise ValueError("unterminated field")
            name = s[i + 1:j]
            if not name:
                raise ValueError("empty field name")
            first = name[0]
            if not ('A' <= first <= 'Z' or 'a' <= first <= 'z' or first == '_'):
                raise ValueError("invalid field name")
            for c in name[1:]:
                if not ('A' <= c <= 'Z' or 'a' <= c <= 'z' or '0' <= c <= '9' or c == '_'):
                    raise ValueError("invalid field name")
            flush()
            out.append(('field', name))
            i = j + 1
        elif ch == '}':
            if i + 1 < n and s[i + 1] == '}':
                text.append('}')
                i += 2
            else:
                raise ValueError("stray closing brace")
        else:
            text.append(ch)
            i += 1
    flush()
    return out

