def purge_in_place(items, targets):
    if items is targets:
        raise ValueError("items and targets must be distinct objects")

    def matches(x):
        for t in targets:
            if type(x) is type(t) and x == t:
                return True
        return False

    kept = [x for x in items if not matches(x)]
    removed = len(items) - len(kept)
    items[:] = kept
    return removed

def splice(items, start, stop, replacement):
    def check_index(i):
        if isinstance(i, bool) or not isinstance(i, int):
            raise ValueError("start/stop must be int, not bool/other")

    check_index(start)
    check_index(stop)
    if not isinstance(replacement, list):
        raise TypeError("replacement must be a list")

    n = len(items)

    def norm(i):
        j = i + n if i < 0 else i
        if j < 0:
            j = 0
        if j > n:
            j = n
        return j

    a = norm(start)
    b = norm(stop)
    if b < a:
        b = a
    return items[:a] + list(replacement) + items[b:]

def sat_add(a, b, bits):
    def check_int(x):
        if isinstance(x, bool) or not isinstance(x, int):
            raise ValueError("expected a non-bool int")
    check_int(a)
    check_int(b)
    check_int(bits)
    if bits < 1:
        raise ValueError("bits must be >= 1")
    lo = -(1 << (bits - 1))
    hi = (1 << (bits - 1)) - 1
    if a < lo or a > hi or b < lo or b > hi:
        raise ValueError("operand out of representable range")
    s = a + b
    if s < lo:
        return lo
    if s > hi:
        return hi
    return s

def div_round_half_away(num, den):
    for v in (num, den):
        if isinstance(v, bool) or not isinstance(v, int):
            raise ValueError("expected a non-bool int")
    if den == 0:
        raise ValueError("denominator must be nonzero")
    negative = (num < 0) != (den < 0)
    n = abs(num)
    d = abs(den)
    q, r = divmod(n, d)
    if 2 * r >= d:
        q += 1
    return -q if negative else q

def add_months(year, month, day, n):
    def check_int(x):
        if isinstance(x, bool) or not isinstance(x, int):
            raise ValueError("expected a non-bool int")

    def is_leap(y):
        return y % 4 == 0 and (y % 100 != 0 or y % 400 == 0)

    def days_in(y, m):
        if m == 2:
            return 29 if is_leap(y) else 28
        return 31 if m in (1, 3, 5, 7, 8, 10, 12) else 30

    for v in (year, month, day, n):
        check_int(v)
    if year < 1:
        raise ValueError("year must be >= 1")
    if month < 1 or month > 12:
        raise ValueError("month out of range")
    if day < 1 or day > days_in(year, month):
        raise ValueError("day out of range")
    total = year * 12 + (month - 1) + n
    new_year, month_index = divmod(total, 12)
    new_month = month_index + 1
    if new_year < 1:
        raise ValueError("resulting year out of range")
    new_day = min(day, days_in(new_year, new_month))
    return (new_year, new_month, new_day)

def apportion(weights, total):
    if isinstance(total, bool) or not isinstance(total, int):
        raise ValueError("total must be a non-bool int")
    if total < 0:
        raise ValueError("total must be >= 0")
    if not isinstance(weights, list) or len(weights) == 0:
        raise ValueError("weights must be a non-empty list")
    for w in weights:
        if isinstance(w, bool) or not isinstance(w, int):
            raise ValueError("weights must be non-bool ints")
        if w < 0:
            raise ValueError("weights must be >= 0")
    s = sum(weights)
    if s == 0:
        raise ValueError("at least one weight must be positive")
    floors = [(w * total) // s for w in weights]
    rems = [(w * total) % s for w in weights]
    r = total - sum(floors)
    order = sorted(range(len(weights)), key=lambda i: (-rems[i], i))
    result = list(floors)
    for i in order[:r]:
        result[i] += 1
    return result

def bucket_counts(values, edges):
    if not isinstance(edges, list) or len(edges) < 2:
        raise ValueError("edges must be a list with at least 2 entries")
    for e in edges:
        if isinstance(e, bool) or not isinstance(e, int):
            raise ValueError("edges must be non-bool ints")
    for i in range(len(edges) - 1):
        if edges[i] >= edges[i + 1]:
            raise ValueError("edges must be strictly increasing")
    if not isinstance(values, list):
        raise ValueError("values must be a list")
    counts = [0] * (len(edges) - 1)
    last = len(edges) - 2
    for v in values:
        if isinstance(v, bool) or not isinstance(v, int):
            raise ValueError("values must be non-bool ints")
        if v < edges[0] or v > edges[-1]:
            raise ValueError("value out of range")
        if v == edges[-1]:
            counts[last] += 1
            continue
        lo = 0
        hi = len(edges) - 1
        while lo + 1 < hi:
            mid = (lo + hi) // 2
            if edges[mid] <= v:
                lo = mid
            else:
                hi = mid
        counts[lo] += 1
    return counts

def format_duration(seconds):
    if isinstance(seconds, bool) or not isinstance(seconds, int):
        raise ValueError("expected a non-bool int")
    sign = "-" if seconds < 0 else ""
    a = abs(seconds)
    if a < 3600:
        m, s = divmod(a, 60)
        return "%s%d:%02d" % (sign, m, s)
    h, rem = divmod(a, 3600)
    m, s = divmod(rem, 60)
    return "%s%d:%02d:%02d" % (sign, h, m, s)

def edit(commands):
    def parse_count(arg):
        if arg == "" or any(c not in "0123456789" for c in arg):
            raise ValueError("bad count")
        n = int(arg)
        if n == 0:
            raise ValueError("bad count")
        return n

    buf = ""
    cur = 0
    undo_stack = []
    for cmd in commands:
        if cmd == "undo":
            if undo_stack:
                buf, cur = undo_stack.pop()
            continue
        sep = cmd.find(" ")
        if sep == -1:
            raise ValueError("bad command")
        verb, arg = cmd[:sep], cmd[sep + 1:]
        if verb == "type":
            if arg == "":
                raise ValueError("bad command")
            undo_stack.append((buf, cur))
            buf = buf[:cur] + arg + buf[cur:]
            cur += len(arg)
        elif verb == "left":
            cur = max(0, cur - parse_count(arg))
        elif verb == "right":
            cur = min(len(buf), cur + parse_count(arg))
        elif verb == "backspace":
            k = min(parse_count(arg), cur)
            if k > 0:
                undo_stack.append((buf, cur))
                buf = buf[:cur - k] + buf[cur:]
                cur -= k
        else:
            raise ValueError("bad command")
    return (buf, cur)

