def outline_paths(lines):
    entries = []
    prev_level = -1
    for line in lines:
        if line.strip() == "":
            continue
        i = 0
        while i < len(line) and line[i] in " \t":
            i += 1
        lead = line[:i]
        if "\t" in lead:
            raise ValueError("tab in indent")
        if len(lead) % 2 != 0:
            raise ValueError("odd indent")
        level = len(lead) // 2
        if level > prev_level + 1:
            raise ValueError("indent jump")
        name = line[i:].rstrip()
        if "/" in name:
            raise ValueError("slash in name")
        entries.append((level, name))
        prev_level = level
    paths = []
    stack = []
    for idx, (level, name) in enumerate(entries):
        del stack[level:]
        stack.append(name)
        next_level = entries[idx + 1][0] if idx + 1 < len(entries) else -1
        if next_level <= level:
            paths.append("/".join(stack))
    return paths

def untilde(s):
    hexd = "0123456789abcdefABCDEF"
    out = []
    i = 0
    while i < len(s):
        c = s[i]
        if c == "~":
            if i + 1 >= len(s):
                raise ValueError("dangling escape")
            e = s[i + 1]
            if e == "~":
                out.append("~")
                i += 2
            elif e == "n":
                out.append("\n")
                i += 2
            elif e == "t":
                out.append("\t")
                i += 2
            elif e == "x":
                h = s[i + 2:i + 4]
                if len(h) < 2 or h[0] not in hexd or h[1] not in hexd:
                    raise ValueError("bad hex")
                out.append(chr(int(h, 16)))
                i += 4
            else:
                raise ValueError("bad escape")
        else:
            if ord(c) < 32:
                raise ValueError("raw control")
            out.append(c)
            i += 1
    return "".join(out)

def decode_varints(data):
    for b in data:
        if isinstance(b, bool) or not isinstance(b, int) or b < 0 or b > 255:
            raise ValueError("bad byte")
    out = []
    i = 0
    n = len(data)
    while i < n:
        u = 0
        shift = 0
        count = 0
        last = 0
        while True:
            if count == 5:
                raise ValueError("too long")
            if i >= n:
                raise ValueError("truncated")
            b = data[i]
            i += 1
            count += 1
            u |= (b & 0x7F) << shift
            shift += 7
            last = b
            if b & 0x80 == 0:
                break
        if count > 1 and last == 0:
            raise ValueError("overlong")
        out.append((u >> 1) ^ -(u & 1))
    return out
